import { GoogleGenAI, Type } from "@google/genai";
import { Ticket, Service, Station, TicketStatus } from "../types";

export const getAiRecommendations = async (
  tickets: Ticket[],
  services: Service[],
  stations: Station[]
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Format data for AI context
  const stats = {
    totalTickets: tickets.length,
    byStatus: {
      completed: tickets.filter(t => t.status === TicketStatus.COMPLETED).length,
      cancelled: tickets.filter(t => t.status === TicketStatus.CANCELLED).length,
      waiting: tickets.filter(t => t.status === TicketStatus.WAITING).length,
    },
    serviceEfficiency: services.map(s => {
      const sTickets = tickets.filter(t => t.serviceId === s.id);
      return {
        service: s.name,
        count: sTickets.length,
        waitAvg: sTickets.length ? 15 : 0 // Simplified for context
      };
    })
  };

  const prompt = `Analyze this QMS (Queue Management System) performance data and provide 3-4 strategic recommendations. 
  Data Summary: ${JSON.stringify(stats)}. 
  Stations: ${stations.length}.
  Provide advice on staffing, module redistribution, and bottleneck mitigation.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            recommendations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  priority: { type: Type.STRING, enum: ["HIGH", "MEDIUM", "LOW"] }
                },
                required: ["title", "description", "priority"]
              }
            }
          },
          required: ["recommendations"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("AI Analysis Error:", error);
    return { recommendations: [] };
  }
};

import { useState, useEffect, useCallback } from 'react';
import { Ticket, TicketStatus, Service, Station, QmsState } from '../types';
import { INITIAL_SERVICES, INITIAL_STATIONS } from '../constants';

export const useQmsStore = () => {
  const [state, setState] = useState<QmsState>(() => {
    const saved = localStorage.getItem('qms_state');
    if (saved) return JSON.parse(saved);
    return {
      services: INITIAL_SERVICES,
      stations: INITIAL_STATIONS,
      tickets: [],
      nextSequence: INITIAL_SERVICES.reduce((acc, s) => ({ ...acc, [s.id]: 101 }), {}),
    };
  });

  useEffect(() => {
    localStorage.setItem('qms_state', JSON.stringify(state));
  }, [state]);

  const addTicket = useCallback((serviceId: string) => {
    setState(prev => {
      const service = prev.services.find(s => s.id === serviceId);
      if (!service) return prev;

      const sequence = prev.nextSequence[serviceId] || 101;
      const code = `${service.prefix}-${sequence}`;

      const newTicket: Ticket = {
        id: crypto.randomUUID(),
        code,
        serviceId,
        status: TicketStatus.WAITING,
        createdAt: Date.now(),
      };

      return {
        ...prev,
        tickets: [...prev.tickets, newTicket],
        nextSequence: {
          ...prev.nextSequence,
          [serviceId]: sequence + 1
        }
      };
    });
  }, []);

  const updateTicketStatus = useCallback((ticketId: string, status: TicketStatus, stationId?: string) => {
    setState(prev => ({
      ...prev,
      tickets: prev.tickets.map(t => {
        if (t.id === ticketId) {
          const updates: Partial<Ticket> = { status };
          if (status === TicketStatus.CALLING) updates.calledAt = Date.now();
          if (status === TicketStatus.ATTENDING) updates.startedAt = Date.now();
          if (status === TicketStatus.COMPLETED || status === TicketStatus.CANCELLED) updates.endedAt = Date.now();
          if (stationId) updates.stationId = stationId;
          return { ...t, ...updates };
        }
        return t;
      })
    }));
  }, []);

  const resetSystem = useCallback(() => {
    if (confirm("¿Estás seguro de reiniciar todo el sistema? Se borrarán todos los turnos.")) {
      setState(prev => ({
        ...prev,
        tickets: [],
        nextSequence: prev.services.reduce((acc, s) => ({ ...acc, [s.id]: 101 }), {}),
      }));
    }
  }, []);

  return {
    state,
    addTicket,
    updateTicketStatus,
    resetSystem,
  };
};

import React, { useState } from 'react';
import { Service } from '../types';

interface TotemViewProps {
  services: Service[];
  onIssueTicket: (serviceId: string) => void;
}

const TotemView: React.FC<TotemViewProps> = ({ services, onIssueTicket }) => {
  const [lastIssued, setLastIssued] = useState<string | null>(null);

  const handleIssue = (serviceId: string) => {
    onIssueTicket(serviceId);
    const service = services.find(s => s.id === serviceId);
    setLastIssued(service?.name || "Turno");
    setTimeout(() => setLastIssued(null), 3000);
  };

  return (
    <div className="max-w-4xl mx-auto p-6 text-center">
      <header className="mb-12">
        <h1 className="text-4xl font-bold text-slate-800 mb-2">Bienvenido a QMS Pro</h1>
        <p className="text-xl text-slate-500">Por favor, seleccione el servicio que requiere</p>
      </header>

      {lastIssued && (
        <div className="mb-8 p-4 bg-green-100 text-green-700 rounded-xl border border-green-200 animate-bounce">
          ¡Ticket para <span className="font-bold">{lastIssued}</span> generado exitosamente!
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {services.map(service => (
          <button
            key={service.id}
            onClick={() => handleIssue(service.id)}
            className="group relative h-48 rounded-3xl overflow-hidden shadow-lg transition-all hover:scale-[1.02] active:scale-95"
            style={{ backgroundColor: service.color }}
          >
            <div className="absolute inset-0 bg-black opacity-10 group-hover:opacity-0 transition-opacity" />
            <div className="relative p-8 flex flex-col items-center justify-center text-white">
              <span className="text-3xl font-bold mb-2">{service.name}</span>
              <p className="text-white/80">{service.description}</p>
              <div className="mt-4 px-4 py-2 bg-white/20 rounded-full text-sm font-semibold border border-white/30">
                Seleccionar
              </div>
            </div>
          </button>
        ))}
      </div>

      <footer className="mt-16 text-slate-400 text-sm">
        Sistema de Gestión de Turnos Inteligente • v2.1
      </footer>
    </div>
  );
};

