import React, { useState, useMemo, useEffect } from 'react';
import { Ticket, Station, Service, TicketStatus } from '../types';

interface StaffViewProps {
  station: Station;
  tickets: Ticket[];
  services: Service[];
  onStatusUpdate: (ticketId: string, status: TicketStatus, stationId: string) => void;
}

const StaffView: React.FC<StaffViewProps> = ({ station, tickets, services, onStatusUpdate }) => {
  const [elapsedTime, setElapsedTime] = useState(0);

  // Filter tickets for this station's services
  const relevantTickets = useMemo(() => 
    tickets.filter(t => station.serviceIds.includes(t.serviceId)),
  [tickets, station.serviceIds]);

  const waitingTickets = relevantTickets.filter(t => t.status === TicketStatus.WAITING);
  const activeTicket = tickets.find(t => t.stationId === station.id && 
    (t.status === TicketStatus.CALLING || t.status === TicketStatus.ATTENDING));

  useEffect(() => {
    let interval: any;
    if (activeTicket?.status === TicketStatus.ATTENDING) {
      interval = setInterval(() => {
        setElapsedTime(Math.floor((Date.now() - (activeTicket.startedAt || Date.now())) / 1000));
      }, 1000);
    } else {
      setElapsedTime(0);
    }
    return () => clearInterval(interval);
  }, [activeTicket]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const currentService = activeTicket ? services.find(s => s.id === activeTicket.serviceId) : null;

  return (
    <div className="max-w-5xl mx-auto p-6 space-y-6">
      <div className="flex justify-between items-center bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">{station.name}</h2>
          <p className="text-slate-500">Operador: <span className="font-semibold text-slate-700">{station.operatorName}</span></p>
        </div>
        <div className="flex gap-2">
          {station.serviceIds.map(id => {
            const s = services.find(sv => sv.id === id);
            return (
              <span key={id} className="px-3 py-1 text-xs font-bold text-white rounded-full" style={{ backgroundColor: s?.color }}>
                {s?.prefix}
              </span>
            );
          })}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left: Queue */}
        <div className="lg:col-span-1 bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="p-4 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
            <h3 className="font-bold text-slate-700">En Espera ({waitingTickets.length})</h3>
          </div>
          <div className="divide-y divide-slate-100 max-h-[500px] overflow-y-auto">
            {waitingTickets.length === 0 ? (
              <div className="p-8 text-center text-slate-400 italic">No hay tickets en espera</div>
            ) : (
              waitingTickets.map(t => (
                <div key={t.id} className="p-4 flex justify-between items-center hover:bg-slate-50 transition-colors">
                  <span className="text-lg font-bold text-slate-700">{t.code}</span>
                  <button 
                    onClick={() => onStatusUpdate(t.id, TicketStatus.CALLING, station.id)}
                    disabled={!!activeTicket}
                    className="px-4 py-1.5 bg-blue-600 text-white text-sm font-bold rounded-lg hover:bg-blue-700 disabled:opacity-30 disabled:cursor-not-allowed transition-all"
                  >
                    Llamar
                  </button>
                </div>
              ))
            )}
          </div>
        </div>

        {/* Right: Active Turn Management */}
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden">
            <div className="p-8 text-center">
              {activeTicket ? (
                <div className="space-y-6">
                  <div className="inline-block px-4 py-2 rounded-full text-xs font-black uppercase tracking-widest text-white mb-4" style={{ backgroundColor: currentService?.color }}>
                    {currentService?.name}
                  </div>
                  <h1 className="text-8xl font-black text-slate-900 tracking-tighter">{activeTicket.code}</h1>

                  {activeTicket.status === TicketStatus.CALLING ? (
                    <div className="py-8 space-y-4">
                      <p className="text-blue-600 font-bold animate-pulse text-xl">Llamando al paciente...</p>
                      <div className="flex justify-center gap-4">
                        <button 
                          onClick={() => onStatusUpdate(activeTicket.id, TicketStatus.ATTENDING, station.id)}
                          className="px-12 py-4 bg-green-600 text-white font-black text-xl rounded-2xl shadow-lg shadow-green-200 hover:bg-green-700 transform hover:-translate-y-1 transition-all"
                        >
                          Iniciar Atención
                        </button>
                        <button 
                          onClick={() => onStatusUpdate(activeTicket.id, TicketStatus.CANCELLED, station.id)}
                          className="px-8 py-4 bg-red-50 text-red-600 font-bold rounded-2xl hover:bg-red-100 transition-all"
                        >
                          No se presentó
                        </button>
                      </div>
                    </div>
                  ) : (
                    <div className="py-8 space-y-6">
                      <div className="text-5xl font-mono font-bold text-slate-700 tabular-nums">
                        {formatTime(elapsedTime)}
                      </div>
                      <p className="text-slate-500 font-medium">Cronómetro de atención en curso</p>
                      <div className="flex justify-center gap-4">
                        <button 
                          onClick={() => onStatusUpdate(activeTicket.id, TicketStatus.COMPLETED, station.id)}
                          className="px-12 py-4 bg-slate-800 text-white font-black text-xl rounded-2xl shadow-lg shadow-slate-300 hover:bg-slate-900 transform hover:-translate-y-1 transition-all"
                        >
                          Finalizar Turno
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              ) : (
                <div className="py-16 space-y-4">
                  <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mx-auto text-slate-400">
                    <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v4"/><path d="m16.2 7.8 2.9-2.9"/><path d="M18 12h4"/><path d="m16.2 16.2 2.9 2.9"/><path d="M12 18v4"/><path d="m4.9 19.1 2.9-2.9"/><path d="M2 12h4"/><path d="m4.9 4.9 2.9 2.9"/></svg>
                  </div>
                  <h2 className="text-2xl font-bold text-slate-800">Estación Disponible</h2>
                  <p className="text-slate-500 max-w-xs mx-auto">Seleccione un ticket de la lista de espera para comenzar la atención.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default StaffView;

