import React, { useState, useEffect, useMemo } from 'react';
import { Ticket, Service, Station, TicketStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { getAiRecommendations } from '../services/gemini';
import { ICONS } from '../constants.tsx';

interface DashboardViewProps {
  tickets: Ticket[];
  services: Service[];
  stations: Station[];
}

const DashboardView: React.FC<DashboardViewProps> = ({ tickets, services, stations }) => {
  const [aiData, setAiData] = useState<any>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  // Statistics Calculation
  const stats = useMemo(() => {
    const total = tickets.length;
    const completed = tickets.filter(t => t.status === TicketStatus.COMPLETED).length;
    const waiting = tickets.filter(t => t.status === TicketStatus.WAITING).length;
    const efficiency = total ? Math.round((completed / total) * 100) : 0;

    const dataByService = services.map(s => ({
      name: s.name,
      value: tickets.filter(t => t.serviceId === s.id).length,
      color: s.color
    }));

    return { total, completed, waiting, efficiency, dataByService };
  }, [tickets, services]);

  const fetchAiAdvice = async () => {
    setLoadingAi(true);
    const data = await getAiRecommendations(tickets, services, stations);
    setAiData(data);
    setLoadingAi(false);
  };

  useEffect(() => {
    // Initial fetch
    fetchAiAdvice();
    // Refresh every 5 minutes
    const interval = setInterval(fetchAiAdvice, 300000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="max-w-7xl mx-auto p-6 space-y-8 pb-12">
      <header className="flex justify-between items-end">
        <div>
          <h1 className="text-3xl font-black text-slate-900">Dashboard Estratégico</h1>
          <p className="text-slate-500">Monitoreo en tiempo real de la carga operativa</p>
        </div>
        <button 
          onClick={fetchAiAdvice}
          disabled={loadingAi}
          className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white rounded-xl hover:bg-slate-800 disabled:opacity-50 transition-all font-bold"
        >
          {loadingAi ? (
            <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
          ) : (
            <ICONS.Activity />
          )}
          {loadingAi ? 'Analizando...' : 'Recargar Análisis IA'}
        </button>
      </header>

      {/* KPI Row */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {[
          { label: 'Total Turnos', value: stats.total, icon: 'Users', color: 'blue' },
          { label: 'Atendidos', value: stats.completed, icon: 'Activity', color: 'green' },
          { label: 'En Fila', value: stats.waiting, icon: 'Terminal', color: 'amber' },
          { label: 'Eficiencia', value: `${stats.efficiency}%`, icon: 'Activity', color: 'purple' },
        ].map((kpi, i) => (
          <div key={i} className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
            <p className="text-slate-500 text-sm font-bold uppercase tracking-wider mb-1">{kpi.label}</p>
            <p className="text-4xl font-black text-slate-900">{kpi.value}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Main Chart */}
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
          <h3 className="text-xl font-bold text-slate-800 mb-8">Demanda por Servicio</h3>
          <div className="h-[400px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.dataByService}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b'}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b'}} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)'}}
                />
                <Bar dataKey="value" radius={[10, 10, 0, 0]}>
                  {stats.dataByService.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* AI Recommendations */}
        <div className="bg-slate-900 rounded-[2.5rem] p-8 text-white">
          <div className="flex items-center gap-3 mb-8">
             <div className="p-2 bg-blue-500 rounded-lg">
               <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v2"/><path d="m4.93 4.93 1.41 1.41"/><path d="M2 12h2"/><path d="m4.93 19.07 1.41-1.41"/><path d="M12 20v2"/><path d="m19.07 19.07-1.41-1.41"/><path d="M20 12h2"/><path d="m19.07 4.93-1.41 1.41"/><path d="M12 12a4 4 0 1 0 0-8 4 4 0 0 0 0 8Z"/><path d="M12 12v10"/><path d="m8 14 4 2 4-2"/></svg>
             </div>
             <h3 className="text-xl font-bold">Auditoría Inteligente</h3>
          </div>

          <div className="space-y-6">
            {aiData?.recommendations?.map((rec: any, idx: number) => (
              <div key={idx} className="p-5 bg-white/5 border border-white/10 rounded-2xl">
                <div className="flex justify-between items-start mb-2">
                  <h4 className="font-bold text-blue-400">{rec.title}</h4>
                  <span className={`text-[10px] font-black px-2 py-0.5 rounded-full ${
                    rec.priority === 'HIGH' ? 'bg-red-500 text-white' : 'bg-slate-700 text-slate-300'
                  }`}>
                    {rec.priority}
                  </span>
                </div>
                <p className="text-sm text-slate-400 leading-relaxed">{rec.description}</p>
              </div>
            ))}
            {!aiData && !loadingAi && (
              <p className="text-slate-500 italic text-center py-12">No hay recomendaciones disponibles actualmente.</p>
            )}
            {loadingAi && (
              <div className="space-y-4 animate-pulse">
                {[1,2,3].map(i => <div key={i} className="h-24 bg-white/5 rounded-2xl" />)}
              </div>
            )}
          </div>

          <div className="mt-12 p-6 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-3xl">
             <p className="text-sm font-bold mb-1">QMS Pro Insights</p>
             <p className="text-xs text-white/70">Análisis basado en patrones de tráfico y tiempos de respuesta históricos.</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DashboardView;

