export enum TicketStatus {
  WAITING = 'WAITING',
  CALLING = 'CALLING',
  ATTENDING = 'ATTENDING',
  COMPLETED = 'COMPLETED',
  CANCELLED = 'CANCELLED'
}

export enum UserRole {
  SUPERADMIN = 'SUPERADMIN',
  ADMIN = 'ADMIN',
  STAFF = 'STAFF',
  TOTEM = 'TOTEM'
}

export interface User {
  id: string;
  username: string;
  role: UserRole;
  name: string;
}

export interface Service {
  id: string;
  name: string;
  prefix: string;
  color: string;
  description: string;
}

export interface Station {
  id: string;
  name: string;
  operatorName: string;
  serviceIds: string[]; // Services this station can handle
}

export interface Ticket {
  id: string;
  code: string;
  serviceId: string;
  status: TicketStatus;
  createdAt: number;
  calledAt?: number;
  startedAt?: number;
  endedAt?: number;
  stationId?: string;
}

export interface QmsState {
  services: Service[];
  stations: Station[];
  tickets: Ticket[];
  nextSequence: Record<string, number>;
  user: User | null;
}

import { useState, useEffect, useCallback } from 'react';
import { Ticket, TicketStatus, Service, Station, QmsState, User, UserRole } from '../types';
import { INITIAL_SERVICES, INITIAL_STATIONS } from '../constants';

export const useQmsStore = () => {
  const [state, setState] = useState<QmsState>(() => {
    const saved = localStorage.getItem('qms_state');
    if (saved) {
      const parsed = JSON.parse(saved);
      return {
        ...parsed,
        user: parsed.user || null
      };
    }
    return {
      services: INITIAL_SERVICES,
      stations: INITIAL_STATIONS,
      tickets: [],
      nextSequence: INITIAL_SERVICES.reduce((acc, s) => ({ ...acc, [s.id]: 101 }), {}),
      user: null,
    };
  });

  useEffect(() => {
    localStorage.setItem('qms_state', JSON.stringify(state));
  }, [state]);

  const login = useCallback((role: UserRole) => {
    const mockUser: User = {
      id: crypto.randomUUID(),
      username: role.toLowerCase(),
      role: role,
      name: role.charAt(0) + role.slice(1).toLowerCase(),
    };
    setState(prev => ({ ...prev, user: mockUser }));
  }, []);

  const logout = useCallback(() => {
    setState(prev => ({ ...prev, user: null }));
  }, []);

  const addTicket = useCallback((serviceId: string) => {
    setState(prev => {
      const service = prev.services.find(s => s.id === serviceId);
      if (!service) return prev;

      const sequence = prev.nextSequence[serviceId] || 101;
      const code = `${service.prefix}-${sequence}`;

      const newTicket: Ticket = {
        id: crypto.randomUUID(),
        code,
        serviceId,
        status: TicketStatus.WAITING,
        createdAt: Date.now(),
      };

      return {
        ...prev,
        tickets: [...prev.tickets, newTicket],
        nextSequence: {
          ...prev.nextSequence,
          [serviceId]: sequence + 1
        }
      };
    });
  }, []);

  const updateTicketStatus = useCallback((ticketId: string, status: TicketStatus, stationId?: string) => {
    setState(prev => ({
      ...prev,
      tickets: prev.tickets.map(t => {
        if (t.id === ticketId) {
          const updates: Partial<Ticket> = { status };
          if (status === TicketStatus.CALLING) updates.calledAt = Date.now();
          if (status === TicketStatus.ATTENDING) updates.startedAt = Date.now();
          if (status === TicketStatus.COMPLETED || status === TicketStatus.CANCELLED) updates.endedAt = Date.now();
          if (stationId) updates.stationId = stationId;
          return { ...t, ...updates };
        }
        return t;
      })
    }));
  }, []);

  const resetSystem = useCallback(() => {
    if (confirm("¿Estás seguro de reiniciar todo el sistema? Se borrarán todos los turnos.")) {
      setState(prev => ({
        ...prev,
        tickets: [],
        nextSequence: prev.services.reduce((acc, s) => ({ ...acc, [s.id]: 101 }), {}),
      }));
    }
  }, []);

  return {
    state,
    addTicket,
    updateTicketStatus,
    resetSystem,
    login,
    logout
  };
};

