import React, { useState, useMemo, useEffect } from 'react';
import { Ticket, Station, Service, TicketStatus } from '../types';

interface StaffViewProps {
  station: Station;
  tickets: Ticket[];
  services: Service[];
  onStatusUpdate: (ticketId: string, status: TicketStatus, stationId: string) => void;
}

const StaffView: React.FC<StaffViewProps> = ({ station, tickets, services, onStatusUpdate }) => {
  const [elapsedTime, setElapsedTime] = useState(0);

  const relevantTickets = useMemo(() => 
    tickets.filter(t => station.serviceIds.includes(t.serviceId)),
  [tickets, station.serviceIds]);

  const waitingTickets = relevantTickets.filter(t => t.status === TicketStatus.WAITING);
  const activeTicket = tickets.find(t => t.stationId === station.id && 
    (t.status === TicketStatus.CALLING || t.status === TicketStatus.ATTENDING));

  useEffect(() => {
    let interval: any;
    if (activeTicket?.status === TicketStatus.ATTENDING) {
      interval = setInterval(() => {
        setElapsedTime(Math.floor((Date.now() - (activeTicket.startedAt || Date.now())) / 1000));
      }, 1000);
    } else {
      setElapsedTime(0);
    }
    return () => clearInterval(interval);
  }, [activeTicket]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const currentService = activeTicket ? services.find(s => s.id === activeTicket.serviceId) : null;

  return (
    <div className="w-full max-w-5xl mx-auto p-4 space-y-4 animate-fade-in">
      <div className="bg-white p-5 rounded-3xl shadow-sm border border-slate-100 flex justify-between items-center">
        <div>
          <div className="flex items-center gap-2 mb-1">
            <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Módulo Operativo Activo</p>
          </div>
          <h2 className="text-xl font-black text-slate-900 tracking-tight">{station.name}</h2>
          <p className="text-xs text-slate-500 font-medium">Op: <span className="text-slate-900 font-bold">{station.operatorName}</span></p>
        </div>
        <div className="flex -space-x-1.5">
          {station.serviceIds.map(id => {
            const s = services.find(sv => sv.id === id);
            return (
              <div key={id} title={s?.name} className="w-8 h-8 rounded-full border-2 border-white flex items-center justify-center text-[8px] font-black text-white shadow-sm" style={{ backgroundColor: s?.color }}>
                {s?.prefix}
              </div>
            );
          })}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-4">
        {/* Queue Column */}
        <div className="lg:col-span-4 bg-white rounded-[2rem] shadow-sm border border-slate-100 flex flex-col overflow-hidden">
          <div className="p-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
            <h3 className="font-black text-slate-800 uppercase tracking-wider text-[10px]">Lista de Espera</h3>
            <span className="bg-slate-900 text-white text-[9px] font-black px-1.5 py-0.5 rounded-md">{waitingTickets.length}</span>
          </div>
          <div className="flex-grow overflow-y-auto max-h-[350px] divide-y divide-slate-50">
            {waitingTickets.length === 0 ? (
              <div className="p-8 text-center text-slate-400">
                <p className="font-bold italic text-xs">Sin pendientes</p>
              </div>
            ) : (
              waitingTickets.map((t, idx) => (
                <div key={t.id} className="p-4 flex justify-between items-center hover:bg-slate-50 transition-colors animate-fade-in" style={{ animationDelay: `${idx * 0.05}s` }}>
                  <div>
                    <span className="text-[9px] font-black text-slate-400 uppercase block">Paciente</span>
                    <span className="text-lg font-black text-slate-900 tracking-tighter">{t.code}</span>
                  </div>
                  <button 
                    onClick={() => onStatusUpdate(t.id, TicketStatus.CALLING, station.id)}
                    disabled={!!activeTicket}
                    className="px-4 py-2 bg-blue-600 text-white text-[10px] font-black uppercase tracking-widest rounded-lg hover:bg-blue-700 disabled:opacity-20 transition-all shadow-md shadow-blue-100"
                  >
                    Llamar
                  </button>
                </div>
              ))
            )}
          </div>
        </div>

        {/* Management Area */}
        <div className="lg:col-span-8">
          <div className="bg-white rounded-[2.5rem] shadow-xl shadow-slate-200/50 border border-slate-100 h-full min-h-[400px] flex flex-col justify-center text-center p-8">
            {activeTicket ? (
              <div className="space-y-6 animate-fade-in">
                <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-[0.2em] text-white mx-auto shadow-sm" style={{ backgroundColor: currentService?.color }}>
                   <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/></svg>
                   {currentService?.name}
                </div>

                <div>
                  <h1 className="text-[80px] font-black text-slate-900 leading-none tracking-tighter">{activeTicket.code}</h1>
                  <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest mt-1">Ticket en Atención</p>
                </div>

                {activeTicket.status === TicketStatus.CALLING ? (
                  <div className="space-y-4 pt-4">
                    <div className="flex flex-col items-center gap-1.5">
                      <div className="flex gap-1">
                        <div className="w-1.5 h-1.5 bg-blue-600 rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
                        <div className="w-1.5 h-1.5 bg-blue-600 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></div>
                        <div className="w-1.5 h-1.5 bg-blue-600 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                      </div>
                      <p className="text-blue-600 font-black uppercase tracking-widest text-[11px]">Notificando Paciente</p>
                    </div>
                    <div className="flex justify-center gap-3">
                      <button 
                        onClick={() => onStatusUpdate(activeTicket.id, TicketStatus.ATTENDING, station.id)}
                        className="flex-1 max-w-[180px] py-4 bg-emerald-600 text-white font-black rounded-xl shadow-lg shadow-emerald-100 hover:bg-emerald-700 active:scale-95 transition-all text-base"
                      >
                        Iniciar
                      </button>
                      <button 
                        onClick={() => onStatusUpdate(activeTicket.id, TicketStatus.CANCELLED, station.id)}
                        className="px-6 py-4 bg-red-50 text-red-600 font-black rounded-xl hover:bg-red-100 active:scale-95 transition-all text-[10px] uppercase tracking-widest"
                      >
                        Ausente
                      </button>
                    </div>
                  </div>
                ) : (
                  <div className="space-y-6 pt-4">
                    <div className="bg-slate-50 inline-block px-8 py-4 rounded-2xl border border-slate-100">
                      <div className="text-4xl font-mono font-black text-slate-800 tracking-tight tabular-nums">
                        {formatTime(elapsedTime)}
                      </div>
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">Tiempo Transcurrido</p>
                    </div>
                    <button 
                      onClick={() => onStatusUpdate(activeTicket.id, TicketStatus.COMPLETED, station.id)}
                      className="w-full max-w-[320px] py-4 bg-slate-900 text-white font-black rounded-xl shadow-xl shadow-slate-300 hover:bg-slate-800 active:scale-95 transition-all text-lg"
                    >
                      Finalizar Atención
                    </button>
                  </div>
                )}
              </div>
            ) : (
              <div className="space-y-4 py-8 opacity-60">
                <div className="w-24 h-24 bg-slate-50 rounded-[2rem] border border-slate-100 flex items-center justify-center mx-auto text-slate-200">
                  <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v4"/><path d="m16.2 7.8 2.9-2.9"/><path d="M18 12h4"/><path d="m16.2 16.2 2.9 2.9"/><path d="M12 18v4"/><path d="m4.9 19.1 2.9-2.9"/><path d="M2 12h4"/><path d="m4.9 4.9 2.9 2.9"/></svg>
                </div>
                <div className="max-w-xs mx-auto">
                  <h3 className="text-xl font-black text-slate-900 tracking-tight mb-1">Módulo Disponible</h3>
                  <p className="text-xs text-slate-500 font-medium leading-tight">Listo para el próximo paciente.</p>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default StaffView;

import React, { useEffect, useState, useMemo } from 'react';
import { Ticket, Station, TicketStatus, Service } from '../types';

interface PublicDisplayViewProps {
  tickets: Ticket[];
  stations: Station[];
  services: Service[];
}

const PublicDisplayView: React.FC<PublicDisplayViewProps> = ({ tickets, stations, services }) => {
  const [lastCallId, setLastCallId] = useState<string | null>(null);
  const [now, setNow] = useState(new Date());

  // Update time every second
  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const activeCalls = useMemo(() => 
    tickets
      .filter(t => t.status === TicketStatus.CALLING || t.status === TicketStatus.ATTENDING)
      .sort((a, b) => (b.calledAt || 0) - (a.calledAt || 0))
      .slice(0, 5),
  [tickets]);

  const waitingList = useMemo(() => 
    tickets
      .filter(t => t.status === TicketStatus.WAITING)
      .sort((a, b) => a.createdAt - b.createdAt)
      .slice(0, 8),
  [tickets]);

  useEffect(() => {
    const calling = tickets.find(t => t.status === TicketStatus.CALLING);
    if (calling && calling.id !== lastCallId) {
      setLastCallId(calling.id);
    }
  }, [tickets, lastCallId]);

  return (
    <div className="min-h-screen bg-[#0f172a] text-white p-8 font-sans flex flex-col overflow-hidden">
      {/* Header with Date and Time */}
      <header className="flex justify-between items-start mb-8 animate-fade-in">
