          </div>
          <div>
            <h1 className="text-3xl font-black tracking-tighter uppercase">GES<span className="text-blue-500">FIL</span></h1>
            <p className="text-slate-500 font-black uppercase tracking-[0.3em] text-[8px] mt-0.5">Medical Display Center</p>
          </div>
        </div>

        <div className="flex flex-col items-end">
          <div className="text-5xl font-mono font-bold tracking-tight leading-none tabular-nums">
            {now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
          </div>
          <div className="text-sm font-bold text-slate-400 mt-1.5 uppercase tracking-widest">
            {now.toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}
          </div>
        </div>
      </header>

      <main className="flex-grow grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left Section: Active Calls */}
