                <h3 className="text-xl font-black tracking-tight text-white uppercase">Próximos Turnos</h3>
                <span className="bg-blue-600 text-[9px] font-black px-2.5 py-0.5 rounded-full uppercase tracking-widest">Fila: {tickets.filter(t => t.status === TicketStatus.WAITING).length}</span>
