import React, { useMemo } from 'react';
import { Ticket, Service, Station, TicketStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface DashboardViewProps {
  tickets: Ticket[];
  services: Service[];
  stations: Station[];
}

const DashboardView: React.FC<DashboardViewProps> = ({ tickets, services, stations }) => {
  const stats = useMemo(() => {
    const total = tickets.length;
    const completed = tickets.filter(t => t.status === TicketStatus.COMPLETED).length;
    const waiting = tickets.filter(t => t.status === TicketStatus.WAITING).length;
    const cancelled = tickets.filter(t => t.status === TicketStatus.CANCELLED).length;
    const efficiency = total ? Math.round(((completed) / (total - waiting || 1)) * 100) : 0;

    const dataByService = services.map(s => ({
      name: s.name,
      value: tickets.filter(t => t.serviceId === s.id).length,
      color: s.color
    }));

    return { total, completed, waiting, efficiency, cancelled, dataByService };
  }, [tickets, services]);

  return (
    <div className="max-w-6xl mx-auto p-6 space-y-8 animate-fade-in">
      <header className="flex justify-between items-end border-b border-slate-100 pb-6">
        <div>
          <div className="flex items-center gap-2 mb-1.5">
             <div className="w-1.5 h-1.5 bg-blue-600 rounded-full"></div>
             <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">Business Intelligence</p>
          </div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Monitor de Desempeño</h1>
          <p className="text-sm text-slate-500 font-medium">Visualización de métricas críticas GESFIL</p>
        </div>
        <div className="bg-white px-4 py-2 rounded-xl border border-slate-100 shadow-sm font-bold text-slate-700 flex items-center gap-2 text-xs">
          <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full"></span>
          Directo: {new Date().toLocaleDateString()}
        </div>
      </header>

      {/* KPI Section */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {[
          { label: 'Volumen Total', value: stats.total, sub: 'Emitidos', color: 'bg-blue-600' },
          { label: 'Tasa Exito', value: `${stats.efficiency}%`, sub: 'Efectivo', color: 'bg-emerald-600' },
          { label: 'En Fila', value: stats.waiting, sub: 'Pendientes', color: 'bg-amber-500' },
          { label: 'Deserciones', value: stats.cancelled, sub: 'Cancelados', color: 'bg-slate-800' },
        ].map((kpi, i) => (
          <div key={i} className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 fluid-card">
            <div className="flex justify-between items-start mb-3">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{kpi.label}</p>
              <div className={`w-6 h-6 ${kpi.color} rounded-lg shadow-md opacity-20`}></div>
            </div>
            <p className="text-4xl font-black text-slate-900 tracking-tighter mb-0.5">{kpi.value}</p>
            <p className="text-[10px] font-bold text-slate-400">{kpi.sub}</p>
          </div>
        ))}
      </div>

      <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <div className="flex justify-between items-center mb-10">
          <h3 className="text-xl font-black text-slate-900 tracking-tight">Demanda por Área</h3>
          <div className="flex gap-3">
             {services.map(s => (
               <div key={s.id} className="flex items-center gap-1.5">
                 <div className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: s.color }}></div>
                 <span className="text-[9px] font-bold text-slate-500 uppercase">{s.prefix}</span>
               </div>
             ))}
          </div>
        </div>
        <div className="h-[350px]">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={stats.dataByService} margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
              <CartesianGrid strokeDasharray="8 8" vertical={false} stroke="#f1f5f9" />
              <XAxis 
                dataKey="name" 
                axisLine={false} 
                tickLine={false} 
                tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} 
                dy={10}
              />
              <YAxis 
                axisLine={false} 
                tickLine={false} 
                tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} 
              />
              <Tooltip 
                cursor={{fill: '#f8fafc'}}
                contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 20px 40px -10px rgb(0 0 0 / 0.1)', padding: '12px'}}
                itemStyle={{fontWeight: 900, fontSize: '12px'}}
              />
              <Bar dataKey="value" radius={[12, 12, 0, 0]} barSize={50}>
                {stats.dataByService.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default DashboardView;

