const App: React.FC = () => {
  const { 
    state, addTicket, updateTicketStatus, resetSystem, login, logout, 
    addUser, updateUser, deleteUser,
    addService, updateService,
    addStation, updateStation
  } = useQmsStore();

  if (!state.currentUser) {
    return <LoginView onLogin={login} />;
  }

  const role = state.currentUser.role;

  return (
    <Router>
      <div className="min-h-screen pb-28 bg-[#f8fafc]">
        <Routes>
          <Route path="/" element={
            [UserRole.TOTEM, UserRole.SUPERADMIN].includes(role) 
              ? <TotemView services={state.services.filter(s => s.active)} onIssueTicket={addTicket} /> 
              : <Navigate to={role === UserRole.STAFF ? "/staff" : "/admin"} />
          } />

          <Route path="/staff" element={
            [UserRole.STAFF, UserRole.ADMIN, UserRole.SUPERADMIN].includes(role) ? (
              <div className="space-y-6 p-4">
                <div className="flex flex-wrap gap-6 justify-center">
                  {state.stations.filter(s => s.active).map(s => (
                    <StaffView 
                      key={s.id} 
                      station={s} 
                      tickets={state.tickets} 
                      services={state.services} 
                      onStatusUpdate={updateTicketStatus} 
                    />
                  ))}
                </div>
              </div>
            ) : <Navigate to="/" />
          } />

          <Route path="/display" element={<PublicDisplayView tickets={state.tickets} stations={state.stations} services={state.services} />} />

          <Route path="/admin" element={
            [UserRole.ADMIN, UserRole.SUPERADMIN].includes(role) ? (
              <div className="space-y-2">
                <DashboardView tickets={state.tickets} services={state.services} stations={state.stations} />
                <AdminPanel 
                  reset={resetSystem} 
                  userRole={role} 
                  users={state.users}
                  onAddUser={addUser}
                  onUpdateUser={updateUser}
                  onDeleteUser={deleteUser}
                  services={state.services}
                  onAddService={addService}
                  onUpdateService={updateService}
                  stations={state.stations}
                  onAddStation={addStation}
                  onUpdateStation={updateStation}
                />
              </div>
            ) : <Navigate to="/" />
          } />

          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
        <Nav role={role} logout={logout} currentUser={state.currentUser} />
      </div>
    </Router>
  );
};

export default App;

import React, { useMemo } from 'react';
import { Ticket, Service, Station, TicketStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface DashboardViewProps {
  tickets: Ticket[];
  services: Service[];
  stations: Station[];
}

const DashboardView: React.FC<DashboardViewProps> = ({ tickets, services, stations }) => {
  const stats = useMemo(() => {
    const total = tickets.length;
    const completed = tickets.filter(t => t.status === TicketStatus.COMPLETED).length;
    const waiting = tickets.filter(t => t.status === TicketStatus.WAITING).length;
    const cancelled = tickets.filter(t => t.status === TicketStatus.CANCELLED).length;
    const efficiency = total ? Math.round(((completed) / (total - waiting || 1)) * 100) : 0;

    const dataByService = services.map(s => {
      const sTickets = tickets.filter(t => t.serviceId === s.id);
      const sCompleted = sTickets.filter(t => t.status === TicketStatus.COMPLETED);
      const avgWait = sCompleted.length > 0 
        ? Math.round(sCompleted.reduce((acc, t) => acc + ((t.startedAt || 0) - t.createdAt), 0) / sCompleted.length / 60000)
        : 0;

      return {
        name: s.name,
        value: sTickets.length,
        completed: sCompleted.length,
        avgWait,
        color: s.color
      };
    });

    const recentTickets = [...tickets].sort((a, b) => b.createdAt - a.createdAt).slice(0, 5);

    return { total, completed, waiting, efficiency, cancelled, dataByService, recentTickets };
  }, [tickets, services]);

  return (
