             <div className="w-1.5 h-1.5 bg-blue-600 rounded-full"></div>
             <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">Consola de Gestión Administrativa</p>
          </div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">GESFIL Business Hub</h1>
          <p className="text-sm text-slate-500 font-medium">Control operativo y gestión de flujo de pacientes</p>
        </div>
        <div className="bg-white px-4 py-2 rounded-xl border border-slate-100 shadow-sm font-bold text-slate-700 flex items-center gap-2 text-xs">
          <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
          Estado: Operativo
        </div>
      </header>

      {/* KPI Section */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {[
          { label: 'Turnos Hoy', value: stats.total, sub: 'Volumen diario', color: 'bg-blue-600' },
          { label: 'Resolución', value: `${stats.efficiency}%`, sub: 'Tasa de éxito', color: 'bg-emerald-600' },
          { label: 'En Cola', value: stats.waiting, sub: 'Pendientes', color: 'bg-amber-500' },
          { label: 'Cancelados', value: stats.cancelled, sub: 'Sin presentación', color: 'bg-slate-800' },
        ].map((kpi, i) => (
          <div key={i} className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-100 transition-all hover:shadow-md">
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">{kpi.label}</p>
            <p className="text-3xl font-black text-slate-900 tracking-tighter">{kpi.value}</p>
            <p className="text-[10px] font-bold text-slate-400">{kpi.sub}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* Demand Chart */}
        <div className="lg:col-span-8 bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-lg font-black text-slate-900 tracking-tight">Demanda Acumulada</h3>
            <div className="flex gap-2">
               {services.map(s => (
                 <div key={s.id} className="w-2 h-2 rounded-full" style={{ backgroundColor: s.color }}></div>
               ))}
