const App: React.FC = () => {
  const { 
    state, addTicket, updateTicketStatus, resetSystem, login, logout, 
    addUser, updateUser, deleteUser,
    addService, updateService,
    addStation, updateStation
  } = useQmsStore();

  if (!state.currentUser) {
    return <LoginView onLogin={login} />;
  }

  const role = state.currentUser.role;
  const user = state.currentUser;

  const filteredStations = state.stations.filter(s => {
    if (!s.active) return false;
    // Si es STAFF, solo ve su módulo asignado
    if (role === UserRole.STAFF) {
      return s.id === user.assignedStationId;
    }
    // ADMIN y SUPERADMIN ven todos los módulos activos
    return true;
  });

  return (
    <Router>
      <div className="min-h-screen pb-28 bg-[#f8fafc]">
        <Routes>
          <Route path="/" element={
            [UserRole.TOTEM, UserRole.ADMIN, UserRole.SUPERADMIN].includes(role) 
              ? <TotemView services={state.services.filter(s => s.active)} onIssueTicket={addTicket} /> 
              : <Navigate to="/staff" />
          } />

          <Route path="/staff" element={
            [UserRole.STAFF, UserRole.ADMIN, UserRole.SUPERADMIN].includes(role) ? (
              <div className="space-y-6 p-4">
                <div className="flex flex-wrap gap-6 justify-center">
                  {filteredStations.length > 0 ? (
                    filteredStations.map(s => (
                      <StaffView 
                        key={s.id} 
                        station={s} 
                        tickets={state.tickets} 
                        services={state.services} 
                        onStatusUpdate={updateTicketStatus} 
                      />
                    ))
                  ) : (
                    <div className="h-[400px] flex flex-col items-center justify-center text-slate-400 max-w-md text-center mx-auto space-y-4">
                       <div className="w-20 h-20 bg-slate-100 rounded-3xl flex items-center justify-center text-3xl">🚫</div>
                       <h2 className="text-xl font-black text-slate-900">Módulo No Asignado</h2>
                       <p className="text-sm font-medium">Su cuenta de operario no tiene un módulo físico vinculado. Contacte al administrador para habilitar su estación de trabajo.</p>
                    </div>
                  )}
                </div>
              </div>
            ) : <Navigate to="/" />
          } />

          <Route path="/display" element={<PublicDisplayView tickets={state.tickets} stations={state.stations} services={state.services} />} />

          <Route path="/admin" element={
            [UserRole.ADMIN, UserRole.SUPERADMIN].includes(role) ? (
              <div className="space-y-2">
                {role === UserRole.ADMIN && (
                   <DashboardView 
                    tickets={state.tickets} 
                    services={state.services} 
                    stations={state.stations} 
                    onToggleService={(id, active) => updateService(id, { active })}
                  />
                )}
                {role === UserRole.SUPERADMIN && (
                   <>
                    <TechnicalInfoView state={state} />
                    <AdminPanel 
                      reset={resetSystem} 
                      userRole={role} 
                      users={state.users}
                      onAddUser={addUser}
                      onUpdateUser={updateUser}
                      onDeleteUser={deleteUser}
                      services={state.services}
                      onAddService={addService}
                      onUpdateService={updateService}
                      stations={state.stations}
                      onAddStation={addStation}
                      onUpdateStation={updateStation}
                    />
                   </>
                )}
              </div>
            ) : <Navigate to="/" />
          } />

          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
        <Nav role={role} logout={logout} currentUser={state.currentUser} />
      </div>
    </Router>
  );
};

export default App;

