                <button 
                  type="submit"
                  className="flex-1 py-3 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700 transition-all"
                >
                  {editingUser ? 'Guardar Cambios' : 'Crear Usuario'}
