import { useState, useEffect, useCallback } from 'react';
import { Ticket, TicketStatus, Service, Station, QmsState, User, UserRole } from '../types';
import { INITIAL_SERVICES, INITIAL_STATIONS } from '../constants';

const DEFAULT_USERS: User[] = [
  { id: 'u1', username: 'superadmin', password: '123', name: 'Super Administrador', role: UserRole.SUPERADMIN },
  { id: 'u2', username: 'admin', password: '123', name: 'Gestor Operativo', role: UserRole.ADMIN },
  { id: 'u3', username: 'staff1', password: '123', name: 'Operario 01', role: UserRole.STAFF, assignedStationId: 's1' },
  { id: 'u4', username: 'totem', password: '123', name: 'Tótem Entrada', role: UserRole.TOTEM },
];

const MOCK_TICKETS: Ticket[] = [
  { id: 't1', code: 'TR-101', serviceId: '1', status: TicketStatus.COMPLETED, createdAt: Date.now() - 3600000, calledAt: Date.now() - 3000000, startedAt: Date.now() - 2900000, endedAt: Date.now() - 2000000, stationId: 's1' },
  { id: 't2', code: 'FM-101', serviceId: '2', status: TicketStatus.WAITING, createdAt: Date.now() - 1800000 },
  { id: 't3', code: 'LB-101', serviceId: '3', status: TicketStatus.CALLING, createdAt: Date.now() - 1200000, calledAt: Date.now() - 100000, stationId: 's3' },
  { id: 't4', code: 'CN-101', serviceId: '4', status: TicketStatus.ATTENDING, createdAt: Date.now() - 2400000, calledAt: Date.now() - 1800000, startedAt: Date.now() - 1500000, stationId: 's1' },
  { id: 't5', code: 'TR-102', serviceId: '1', status: TicketStatus.WAITING, createdAt: Date.now() - 600000 },
  { id: 't6', code: 'FM-102', serviceId: '2', status: TicketStatus.WAITING, createdAt: Date.now() - 300000 },
];

export const useQmsStore = () => {
  const [state, setState] = useState<QmsState>(() => {
    try {
      const saved = localStorage.getItem('qms_state');
      if (saved) {
        const parsed = JSON.parse(saved);

        // Rehydration logic: Ensure that if source code defaults change, they are merged
        const services = (parsed.services || INITIAL_SERVICES).map((s: Service) => ({
          ...s,
          active: s.active ?? true,
          color: s.color || '#3b82f6'
        }));

        const stations = (parsed.stations || INITIAL_STATIONS).map((s: Station) => ({
          ...s,
          active: s.active ?? true
        }));

        return {
          ...parsed,
          services,
          stations,
          users: parsed.users || DEFAULT_USERS,
          tickets: parsed.tickets || MOCK_TICKETS,
          currentUser: parsed.currentUser || null,
          nextSequence: parsed.nextSequence || {}
        };
      }
    } catch (e) {
      console.error("Critical: Storage rehydration failed", e);
    }

    return {
      services: INITIAL_SERVICES.map(s => ({ ...s, active: true })),
      stations: INITIAL_STATIONS.map(s => ({ ...s, active: true })),
      tickets: MOCK_TICKETS,
      nextSequence: INITIAL_SERVICES.reduce((acc, s) => ({ ...acc, [s.id]: 103 }), {}),
      users: DEFAULT_USERS,
      currentUser: null,
    };
  });

  useEffect(() => {
    try {
      localStorage.setItem('qms_state', JSON.stringify(state));
    } catch (e) {
      console.warn("Storage quota exceeded or unavailable", e);
    }
  }, [state]);

  const login = useCallback((username: string, password?: string) => {
    if (!username) return false;
    const foundUser = state.users.find(u => 
      u.username.toLowerCase() === username.trim().toLowerCase() && 
      u.password === password
    );
    if (foundUser) {
      setState(prev => ({ ...prev, currentUser: foundUser }));
      return true;
    }
    return false;
  }, [state.users]);

  const logout = useCallback(() => {
    setState(prev => ({ ...prev, currentUser: null }));
  }, []);

  const addUser = useCallback((userData: Omit<User, 'id'>) => {
    const newUser: User = { ...userData, id: crypto.randomUUID() };
    setState(prev => ({ ...prev, users: [...prev.users, newUser] }));
  }, []);

  const updateUser = useCallback((id: string, updates: Partial<User>) => {
    setState(prev => ({
      ...prev,
      users: prev.users.map(u => u.id === id ? { ...u, ...updates } : u),
      currentUser: prev.currentUser?.id === id ? { ...prev.currentUser, ...updates } : prev.currentUser
    }));
  }, []);

  const deleteUser = useCallback((id: string) => {
    setState(prev => ({
      ...prev,
      users: prev.users.filter(u => u.id !== id),
      currentUser: prev.currentUser?.id === id ? null : prev.currentUser
    }));
  }, []);

  const addService = useCallback((serviceData: Omit<Service, 'id'>) => {
    const newId = crypto.randomUUID();
    const newService: Service = { ...serviceData, id: newId };
    setState(prev => ({
      ...prev,
      services: [...prev.services, newService],
      nextSequence: { ...prev.nextSequence, [newId]: 101 }
    }));
  }, []);

  const updateService = useCallback((id: string, updates: Partial<Service>) => {
    setState(prev => ({
      ...prev,
      services: prev.services.map(s => s.id === id ? { ...s, ...updates } : s)
    }));
  }, []);

  const deleteService = useCallback((id: string) => {
    setState(prev => ({
      ...prev,
      services: prev.services.filter(s => s.id !== id),
      stations: prev.stations.map(st => ({
        ...st,
        serviceIds: st.serviceIds.filter(sid => sid !== id)
      })),
      // Tickets for deleted services are kept but their UI rendering will need fallbacks
    }));
  }, []);

  const addStation = useCallback((stationData: Omit<Station, 'id'>) => {
    const newStation: Station = { ...stationData, id: crypto.randomUUID() };
    setState(prev => ({ ...prev, stations: [...prev.stations, newStation] }));
  }, []);

  const updateStation = useCallback((id: string, updates: Partial<Station>) => {
    setState(prev => ({
      ...prev,
      stations: prev.stations.map(s => s.id === id ? { ...s, ...updates } : s)
    }));
  }, []);

  const deleteStation = useCallback((id: string) => {
    setState(prev => ({
      ...prev,
      stations: prev.stations.filter(s => s.id !== id),
      users: prev.users.map(u => u.assignedStationId === id ? { ...u, assignedStationId: undefined } : u),
      currentUser: prev.currentUser?.assignedStationId === id ? { ...prev.currentUser, assignedStationId: undefined } : prev.currentUser
    }));
  }, []);

  const addTicket = useCallback((serviceId: string) => {
    setState(prev => {
      const service = prev.services.find(s => s.id === serviceId);
      if (!service || !service.active) return prev;

      const sequence = prev.nextSequence[serviceId] || 101;
      const code = `${service.prefix}-${sequence}`;

      const newTicket: Ticket = {
        id: crypto.randomUUID(),
        code,
        serviceId,
        status: TicketStatus.WAITING,
        createdAt: Date.now(),
      };

      return {
        ...prev,
        tickets: [...prev.tickets, newTicket],
        nextSequence: { ...prev.nextSequence, [serviceId]: sequence + 1 }
      };
    });
  }, []);

  const updateTicketStatus = useCallback((ticketId: string, newStatus: TicketStatus, stationId?: string) => {
    setState(prev => {
      const ticketIndex = prev.tickets.findIndex(t => t.id === ticketId);
      if (ticketIndex === -1) return prev;

      const ticket = prev.tickets[ticketIndex];

      // Strict state machine transitions
      const isTerminal = ticket.status === TicketStatus.COMPLETED || ticket.status === TicketStatus.CANCELLED;
      if (isTerminal) return prev;

      const updatedTickets = [...prev.tickets];
      const updates: Partial<Ticket> = { status: newStatus };

      if (newStatus === TicketStatus.CALLING) {
        updates.calledAt = Date.now();
        if (stationId) updates.stationId = stationId;
      } else if (newStatus === TicketStatus.ATTENDING) {
        updates.startedAt = ticket.startedAt || Date.now();
        if (stationId) updates.stationId = stationId;
      } else if (newStatus === TicketStatus.COMPLETED || newStatus === TicketStatus.CANCELLED) {
        updates.endedAt = Date.now();
      }

      updatedTickets[ticketIndex] = { ...ticket, ...updates };

      return { ...prev, tickets: updatedTickets };
    });
  }, []);

  const resetSystem = useCallback(() => {
    if (confirm("Se eliminarán todos los turnos y se reiniciarán las secuencias. Esta acción es irreversible. ¿Continuar?")) {
      setState(prev => ({
        ...prev,
        tickets: [],
        nextSequence: prev.services.reduce((acc, s) => ({ ...acc, [s.id]: 101 }), {}),
      }));
    }
  }, []);

  return {
    state,
    addTicket,
    updateTicketStatus,
    resetSystem,
    login,
    logout,
    addUser,
    updateUser,
    deleteUser,
    addService,
    updateService,
    deleteService,
    addStation,
    updateStation,
    deleteStation
  };
};

import React, { useMemo, useState } from 'react';
import { Ticket, Service, Station, TicketStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
