interface DashboardViewProps {
  tickets: Ticket[];
  services: Service[];
  stations: Station[];
  onToggleService?: (id: string, active: boolean) => void;
}

const DashboardView: React.FC<DashboardViewProps> = ({ tickets, services, stations, onToggleService }) => {
  const [inspectingTicket, setInspectingTicket] = useState<Ticket | null>(null);

  const stats = useMemo(() => {
    const total = tickets.length;
    const completed = tickets.filter(t => t.status === TicketStatus.COMPLETED).length;
    const waiting = tickets.filter(t => t.status === TicketStatus.WAITING).length;
    const cancelled = tickets.filter(t => t.status === TicketStatus.CANCELLED).length;

    // Fix: Precision logic for efficiency to avoid NaN/Infinity
    const resolvedCount = completed + cancelled;
    const closedCount = total - waiting;
    const efficiency = closedCount > 0 ? Math.round((completed / closedCount) * 100) : 0;

    const dataByService = services.map(s => {
      const sTickets = tickets.filter(t => t.serviceId === s.id);
      const sCompleted = sTickets.filter(t => t.status === TicketStatus.COMPLETED);
      const avgWait = sCompleted.length > 0 
        ? Math.round(sCompleted.reduce((acc, t) => acc + ((t.startedAt || 0) - t.createdAt), 0) / sCompleted.length / 60000)
        : 0;

      return {
        name: s.name,
        id: s.id,
        active: s.active,
        value: sTickets.length,
        completed: sCompleted.length,
        avgWait,
        color: s.color
      };
    });

    const recentTickets = [...tickets].sort((a, b) => b.createdAt - a.createdAt).slice(0, 10);

    return { total, completed, waiting, efficiency, cancelled, dataByService, recentTickets };
  }, [tickets, services]);

  return (
    <div className="max-w-6xl mx-auto p-6 space-y-6 animate-fade-in pb-12">
