          <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
          Estado: Operativo
        </div>
      </header>

      {/* KPI Section */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {[
          { label: 'Turnos Hoy', value: stats.total, sub: 'Volumen diario' },
          { label: 'Resolución', value: `${stats.efficiency}%`, sub: 'Tasa de éxito' },
          { label: 'En Cola', value: stats.waiting, sub: 'Pendientes' },
          { label: 'Cancelados', value: stats.cancelled, sub: 'Sin presentación' },
