import { useState, useEffect, useCallback } from 'react';
import { Ticket, TicketStatus, Service, Station, QmsState, User, UserRole } from '../types';
import { INITIAL_SERVICES, INITIAL_STATIONS } from '../constants';

const DEFAULT_USERS: User[] = [
  { id: 'u1', username: 'superadmin', password: '123', name: 'Super Administrador', role: UserRole.SUPERADMIN },
  { id: 'u2', username: 'admin', password: '123', name: 'Gestor Operativo', role: UserRole.ADMIN },
  { id: 'u3', username: 'staff1', password: '123', name: 'Operario 01', role: UserRole.STAFF, assignedStationId: 's1' },
  { id: 'u4', username: 'totem', password: '123', name: 'Tótem Entrada', role: UserRole.TOTEM },
];

const MOCK_TICKETS: Ticket[] = [
  { id: 't1', code: 'TR-101', serviceId: '1', status: TicketStatus.COMPLETED, createdAt: Date.now() - 3600000, calledAt: Date.now() - 3000000, startedAt: Date.now() - 2900000, endedAt: Date.now() - 2000000, stationId: 's1' },
  { id: 't2', code: 'FM-101', serviceId: '2', status: TicketStatus.WAITING, createdAt: Date.now() - 1800000 },
  { id: 't3', code: 'LB-101', serviceId: '3', status: TicketStatus.CALLING, createdAt: Date.now() - 1200000, calledAt: Date.now() - 100000, stationId: 's3' },
  { id: 't4', code: 'CN-101', serviceId: '4', status: TicketStatus.ATTENDING, createdAt: Date.now() - 2400000, calledAt: Date.now() - 1800000, startedAt: Date.now() - 1500000, stationId: 's1' },
];

export const useQmsStore = () => {
  const [state, setState] = useState<QmsState>(() => {
    try {
      const saved = localStorage.getItem('qms_state');
      if (saved) {
        const parsed = JSON.parse(saved);

        // Rehidratación defensiva: Asegura consistencia con tipos actuales
        const services = (parsed.services || INITIAL_SERVICES).map((s: Service) => ({
          ...s,
          active: s.active ?? true
        }));

        const stations = (parsed.stations || INITIAL_STATIONS).map((s: Station) => ({
          ...s,
          active: s.active ?? true
        }));

        return {
          ...parsed,
          services,
          stations,
          users: parsed.users || DEFAULT_USERS,
          tickets: parsed.tickets || MOCK_TICKETS,
          currentUser: parsed.currentUser || null,
          nextSequence: parsed.nextSequence || {}
        };
      }
    } catch (e) {
      console.error("Falla en rehidratación de persistencia:", e);
    }

    return {
      services: INITIAL_SERVICES.map(s => ({ ...s, active: true })),
      stations: INITIAL_STATIONS.map(s => ({ ...s, active: true })),
      tickets: MOCK_TICKETS,
      nextSequence: INITIAL_SERVICES.reduce((acc, s) => ({ ...acc, [s.id]: 102 }), {}),
      users: DEFAULT_USERS,
      currentUser: null,
    };
  });

  useEffect(() => {
    try {
      localStorage.setItem('qms_state', JSON.stringify(state));
    } catch (e) {
      console.error("Error al persistir estado:", e);
    }
  }, [state]);

  const login = useCallback((username: string, password?: string) => {
    if (!username) return false;
    const cleanUsername = username.trim().toLowerCase();
    const foundUser = state.users.find(u => 
      u.username.toLowerCase() === cleanUsername && 
      u.password === password
    );
    if (foundUser) {
      setState(prev => ({ ...prev, currentUser: foundUser }));
      return true;
    }
    return false;
  }, [state.users]);

  const logout = useCallback(() => {
    setState(prev => ({ ...prev, currentUser: null }));
  }, []);

  // --- Usuarios ---
  const addUser = useCallback((userData: Omit<User, 'id'>) => {
    setState(prev => ({ 
      ...prev, 
      users: [...prev.users, { ...userData, id: crypto.randomUUID() }] 
    }));
  }, []);

  const updateUser = useCallback((id: string, updates: Partial<User>) => {
    setState(prev => ({
      ...prev,
      users: prev.users.map(u => u.id === id ? { ...u, ...updates } : u),
      currentUser: prev.currentUser?.id === id ? { ...prev.currentUser, ...updates } : prev.currentUser
    }));
  }, []);

  const deleteUser = useCallback((id: string) => {
    setState(prev => ({
      ...prev,
      users: prev.users.filter(u => u.id !== id),
      currentUser: prev.currentUser?.id === id ? null : prev.currentUser
    }));
  }, []);

  // --- Servicios (Integridad de Estaciones y Secuencias) ---
  const addService = useCallback((serviceData: Omit<Service, 'id'>) => {
    const newId = crypto.randomUUID();
    setState(prev => ({
      ...prev,
      services: [...prev.services, { ...serviceData, id: newId }],
      nextSequence: { ...prev.nextSequence, [newId]: 101 }
    }));
  }, []);

  const updateService = useCallback((id: string, updates: Partial<Service>) => {
    setState(prev => ({
      ...prev,
      services: prev.services.map(s => s.id === id ? { ...s, ...updates } : s)
    }));
  }, []);

  const deleteService = useCallback((id: string) => {
    setState(prev => {
      const nextSequence = { ...prev.nextSequence };
      delete nextSequence[id];

      return {
        ...prev,
        services: prev.services.filter(s => s.id !== id),
        stations: prev.stations.map(st => ({
          ...st,
          serviceIds: st.serviceIds.filter(sid => sid !== id)
        })),
        nextSequence
      };
    });
  }, []);

  // --- Módulos (Integridad de Usuarios) ---
  const addStation = useCallback((stationData: Omit<Station, 'id'>) => {
    setState(prev => ({ 
      ...prev, 
      stations: [...prev.stations, { ...stationData, id: crypto.randomUUID() }] 
    }));
  }, []);

  const updateStation = useCallback((id: string, updates: Partial<Station>) => {
    setState(prev => ({
      ...prev,
      stations: prev.stations.map(s => s.id === id ? { ...s, ...updates } : s)
    }));
  }, []);

  const deleteStation = useCallback((id: string) => {
    setState(prev => ({
      ...prev,
      stations: prev.stations.filter(s => s.id !== id),
      users: prev.users.map(u => u.assignedStationId === id ? { ...u, assignedStationId: undefined } : u),
      currentUser: prev.currentUser?.assignedStationId === id ? { ...prev.currentUser, assignedStationId: undefined } : prev.currentUser
    }));
  }, []);

  // --- Tickets (Control de Flujo Maestro) ---
  const addTicket = useCallback((serviceId: string) => {
    setState(prev => {
      const service = prev.services.find(s => s.id === serviceId);
      if (!service || !service.active) return prev;

      const sequence = prev.nextSequence[serviceId] || 101;
      const code = `${service.prefix}-${sequence}`;

      const newTicket: Ticket = {
        id: crypto.randomUUID(),
        code,
        serviceId,
        status: TicketStatus.WAITING,
        createdAt: Date.now(),
      };

      return {
        ...prev,
        tickets: [...prev.tickets, newTicket],
        nextSequence: { ...prev.nextSequence, [serviceId]: sequence + 1 }
      };
    });
  }, []);

  const updateTicketStatus = useCallback((ticketId: string, newStatus: TicketStatus, stationId?: string) => {
    setState(prev => {
      const ticketIndex = prev.tickets.findIndex(t => t.id === ticketId);
      if (ticketIndex === -1) return prev;

      const ticket = prev.tickets[ticketIndex];

      // Regla de Oro: Un ticket finalizado es inmutable para el proceso operativo
      if (ticket.status === TicketStatus.COMPLETED || ticket.status === TicketStatus.CANCELLED) {
        return prev;
      }

      // Validación Cruzada: El módulo debe tener permiso para el servicio del ticket
      if (stationId && newStatus === TicketStatus.CALLING) {
        const station = prev.stations.find(s => s.id === stationId);
        if (!station || !station.serviceIds.includes(ticket.serviceId)) {
          console.warn("Intento de llamado desde módulo no autorizado para el servicio");
          return prev;
        }
      }

      const updatedTickets = [...prev.tickets];
      const updates: Partial<Ticket> = { status: newStatus };

      if (newStatus === TicketStatus.CALLING) {
        updates.calledAt = Date.now();
        if (stationId) updates.stationId = stationId;
      } else if (newStatus === TicketStatus.ATTENDING) {
        updates.startedAt = ticket.startedAt || Date.now();
      } else if (newStatus === TicketStatus.COMPLETED || newStatus === TicketStatus.CANCELLED) {
        updates.endedAt = Date.now();
      }

      updatedTickets[ticketIndex] = { ...ticket, ...updates };

      return { ...prev, tickets: updatedTickets };
    });
  }, []);

  const resetSystem = useCallback(() => {
    if (window.confirm("Se eliminarán todos los turnos. Las configuraciones de módulos y servicios se mantendrán. ¿Continuar?")) {
      setState(prev => ({
        ...prev,
        tickets: [],
        nextSequence: prev.services.reduce((acc, s) => ({ ...acc, [s.id]: 101 }), {}),
      }));
    }
  }, []);

  return {
    state,
    addTicket,
    updateTicketStatus,
    resetSystem,
    login,
    logout,
    addUser,
    updateUser,
    deleteUser,
    addService,
    updateService,
    deleteService,
    addStation,
    updateStation,
    deleteStation
  };
};

import React, { useMemo, useState } from 'react';
import { Ticket, Service, Station, TicketStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import TicketTraceabilityModal from './TicketTraceabilityModal';

interface DashboardViewProps {
  tickets: Ticket[];
  services: Service[];
  stations: Station[];
  onToggleService?: (id: string, active: boolean) => void;
}

const DashboardView: React.FC<DashboardViewProps> = ({ tickets, services, stations, onToggleService }) => {
  const [inspectingTicket, setInspectingTicket] = useState<Ticket | null>(null);

  const stats = useMemo(() => {
    const total = tickets.length;
    const completed = tickets.filter(t => t.status === TicketStatus.COMPLETED).length;
    const waiting = tickets.filter(t => t.status === TicketStatus.WAITING).length;
    const cancelled = tickets.filter(t => t.status === TicketStatus.CANCELLED).length;

    // Cálculo seguro de eficiencia: (Completados / Finalizados Totales)
    const totalFinalized = total - waiting;
    const efficiency = totalFinalized > 0 ? Math.round((completed / totalFinalized) * 100) : 0;

    const dataByService = services.map(s => {
      const sTickets = tickets.filter(t => t.serviceId === s.id);
      const sCompleted = sTickets.filter(t => t.status === TicketStatus.COMPLETED);

      // Tiempo promedio de espera en minutos
      const avgWait = sCompleted.length > 0 
        ? Math.round(sCompleted.reduce((acc, t) => acc + ((t.startedAt || 0) - t.createdAt), 0) / sCompleted.length / 60000)
        : 0;

      return {
        name: s.name,
        id: s.id,
        active: s.active,
        value: sTickets.length,
        completed: sCompleted.length,
        avgWait,
        color: s.color || '#3b82f6'
      };
    });

    const recentTickets = [...tickets].sort((a, b) => b.createdAt - a.createdAt).slice(0, 10);

    return { total, completed, waiting, efficiency, cancelled, dataByService, recentTickets };
  }, [tickets, services]);

  return (
    <div className="max-w-6xl mx-auto p-6 space-y-6 animate-fade-in pb-12">
      <header className="flex justify-between items-end border-b border-slate-100 pb-6">
        <div>
          <div className="flex items-center gap-2 mb-1.5">
             <div className="w-1.5 h-1.5 bg-blue-600 rounded-full"></div>
             <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">Consola de Gestión Administrativa</p>
          </div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">GESFIL Business Hub</h1>
          <p className="text-sm text-slate-500 font-medium">Control operativo y gestión de flujo de pacientes</p>
        </div>
        <div className="bg-white px-4 py-2 rounded-xl border border-slate-100 shadow-sm font-bold text-slate-700 flex items-center gap-2 text-xs">
          <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
          Estado: Operativo
        </div>
      </header>

      {/* KPI Section */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {[
          { label: 'Turnos Hoy', value: stats.total, sub: 'Volumen diario' },
          { label: 'Resolución', value: `${stats.efficiency}%`, sub: 'Tasa de éxito' },
          { label: 'En Cola', value: stats.waiting, sub: 'Pendientes' },
          { label: 'Cancelados', value: stats.cancelled, sub: 'Sin presentación' },
        ].map((kpi, i) => (
          <div key={i} className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-100 transition-all hover:shadow-md">
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">{kpi.label}</p>
            <p className="text-3xl font-black text-slate-900 tracking-tighter">{kpi.value}</p>
            <p className="text-[10px] font-bold text-slate-400">{kpi.sub}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* Demand Chart */}
        <div className="lg:col-span-8 bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-lg font-black text-slate-900 tracking-tight">Demanda Acumulada</h3>
            <div className="flex gap-2">
               {services.map(s => (
                 <div key={s.id} className="w-2 h-2 rounded-full" style={{ backgroundColor: s.color }}></div>
               ))}
            </div>
          </div>
          <div className="h-[280px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.dataByService} margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="4 4" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 9, fontWeight: 700}} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 9, fontWeight: 700}} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', padding: '8px'}}
                  itemStyle={{fontWeight: 800, fontSize: '11px'}}
                />
                <Bar dataKey="value" radius={[10, 10, 0, 0]} barSize={40}>
                  {stats.dataByService.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Management Panel: Services Toggle */}
        <div className="lg:col-span-4 space-y-4">
           <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <h4 className="text-xs font-black uppercase tracking-widest text-slate-400 mb-4">Gestión de Servicios</h4>
              <div className="space-y-3">
                {stats.dataByService.map(s => (
                  <div key={s.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-2xl border border-slate-100 group">
                    <div className="flex items-center gap-3">
                      <div className="w-2 h-8 rounded-full" style={{ backgroundColor: s.color }}></div>
                      <div>
                        <p className="text-[10px] font-black text-slate-900 leading-none mb-1">{s.name}</p>
                        <p className="text-[9px] text-slate-400 font-bold uppercase">{s.active ? 'Operativo' : 'Pausado'}</p>
                      </div>
                    </div>
                    {onToggleService && (
                      <button 
                        onClick={() => onToggleService(s.id, !s.active)}
                        className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${
                          s.active ? 'bg-emerald-50 text-emerald-600 hover:bg-red-50 hover:text-red-600' : 'bg-slate-200 text-slate-500 hover:bg-emerald-600 hover:text-white'
                        }`}
                      >
                         <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18.36 6.64a9 9 0 1 1-12.73 0"/><line x1="12" y1="2" x2="12" y2="12"/></svg>
                      </button>
                    )}
                  </div>
                ))}
              </div>
           </div>

           <div className="bg-slate-900 p-6 rounded-[2.5rem] text-white shadow-xl">
              <h4 className="text-xs font-black uppercase tracking-widest text-slate-400 mb-4">Salud del Centro</h4>
              <div className="grid grid-cols-2 gap-3">
                <div className="p-3 bg-white/5 rounded-xl border border-white/5 text-center">
                  <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-1">Módulos</p>
                  <p className="text-xl font-black text-emerald-400">{stations.filter(st => st.active).length}</p>
                </div>
                <div className="p-3 bg-white/5 rounded-xl border border-white/5 text-center">
                  <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-1">Espera Máx</p>
                  <p className="text-xl font-black text-amber-400">12m</p>
                </div>
              </div>
           </div>
        </div>

        {/* Recent Activity Table */}
        <div className="lg:col-span-12 bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
           <h3 className="text-lg font-black text-slate-900 tracking-tight mb-4 px-2">Registro Maestro y Trazabilidad</h3>
           <div className="overflow-x-auto">
             <table className="w-full text-left">
               <thead className="bg-slate-50 text-slate-500 text-[9px] uppercase tracking-widest font-bold">
                 <tr>
                   <th className="px-6 py-4">Código</th>
                   <th className="px-6 py-4">Servicio</th>
                   <th className="px-6 py-4">Ingreso</th>
                   <th className="px-6 py-4">Estado</th>
                   <th className="px-6 py-4 text-right">Detalle</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-50">
                 {stats.recentTickets.map(t => {
                   const s = services.find(sv => sv.id === t.serviceId);
                   return (
                     <tr key={t.id} className="text-xs group hover:bg-slate-50/80 transition-colors">
                       <td className="px-6 py-4 font-black text-slate-900">{t.code}</td>
                       <td className="px-6 py-4 text-slate-500 font-bold">{s?.name || 'Desconocido'}</td>
                       <td className="px-6 py-4 text-slate-400 font-medium">{new Date(t.createdAt).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</td>
                       <td className="px-6 py-4">
                         <span className={`px-2.5 py-1 rounded-full text-[8px] font-black uppercase ${
                           t.status === TicketStatus.COMPLETED ? 'bg-emerald-100 text-emerald-700' :
                           t.status === TicketStatus.WAITING ? 'bg-amber-100 text-amber-700' :
                           t.status === TicketStatus.CANCELLED ? 'bg-red-100 text-red-700' :
                           'bg-blue-100 text-blue-700'
                         }`}>
                           {t.status}
                         </span>
                       </td>
                       <td className="px-6 py-4 text-right">
                          <button 
                            onClick={() => setInspectingTicket(t)}
                            className="w-8 h-8 flex items-center justify-center text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all"
                            title="Inspeccionar Ciclo de Vida"
                          >
                             <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><path d="M12 16v-4"/><path d="M12 8h.01"/></svg>
                          </button>
                       </td>
                     </tr>
                   )
                 })}
               </tbody>
             </table>
           </div>
        </div>
      </div>

      {inspectingTicket && (
        <TicketTraceabilityModal 
          ticket={inspectingTicket}
          service={services.find(s => s.id === inspectingTicket.serviceId)}
          station={stations.find(st => st.id === inspectingTicket.stationId)}
          onClose={() => setInspectingTicket(null)}
        />
      )}
    </div>
  );
};

export default DashboardView;

import React, { useState, useMemo, useEffect } from 'react';
import { Ticket, Station, Service, TicketStatus } from '../types';

interface StaffViewProps {
  station: Station;
  tickets: Ticket[];
  services: Service[];
  onStatusUpdate: (ticketId: string, status: TicketStatus, stationId: string) => void;
}

const StaffView: React.FC<StaffViewProps> = ({ station, tickets, services, onStatusUpdate }) => {
  const [elapsedTime, setElapsedTime] = useState(0);

  // Tickets relevantes: Se filtran aquellos cuyos servicios aún existan y estén asignados al módulo
  const relevantTickets = useMemo(() => 
    tickets.filter(t => 
      station.serviceIds.includes(t.serviceId) && 
      services.some(s => s.id === t.serviceId)
    ),
  [tickets, station.serviceIds, services]);

  const waitingTickets = relevantTickets.filter(t => t.status === TicketStatus.WAITING);

  // Ticket activo en este módulo
  const activeTicket = tickets.find(t => t.stationId === station.id && 
    (t.status === TicketStatus.CALLING || t.status === TicketStatus.ATTENDING));

  useEffect(() => {
    let interval: any;
    if (activeTicket?.status === TicketStatus.ATTENDING) {
      interval = setInterval(() => {
        setElapsedTime(Math.floor((Date.now() - (activeTicket.startedAt || Date.now())) / 1000));
      }, 1000);
    } else {
      setElapsedTime(0);
    }
    return () => clearInterval(interval);
  }, [activeTicket]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const getWaitTime = (createdAt: number) => {
    const diff = Math.floor((Date.now() - createdAt) / 60000);
    return diff > 0 ? `${diff}m` : 'Reciente';
  };

  const currentService = activeTicket ? services.find(s => s.id === activeTicket.serviceId) : null;

  return (
    <div className="w-full max-w-5xl mx-auto p-4 space-y-4 animate-fade-in">
      <div className="bg-white p-5 rounded-3xl shadow-sm border border-slate-100 flex justify-between items-center">
        <div>
          <div className="flex items-center gap-2 mb-1">
            <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Módulo Operativo Activo</p>
          </div>
          <h2 className="text-xl font-black text-slate-900 tracking-tight">{station.name}</h2>
          <p className="text-xs text-slate-500 font-medium">Op: <span className="text-slate-900 font-bold">{station.operatorName}</span></p>
        </div>
        <div className="flex -space-x-1.5">
          {station.serviceIds.map(id => {
            const s = services.find(sv => sv.id === id);
            if (!s) return null;
            return (
              <div key={id} title={s.name} className="w-8 h-8 rounded-full border-2 border-white flex items-center justify-center text-[8px] font-black text-white shadow-sm" style={{ backgroundColor: s.color }}>
                {s.prefix}
              </div>
            );
          })}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-4">
        {/* Queue Column */}
        <div className="lg:col-span-4 bg-white rounded-[2rem] shadow-sm border border-slate-100 flex flex-col overflow-hidden">
          <div className="p-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
            <h3 className="font-black text-slate-800 uppercase tracking-wider text-[10px]">Lista de Espera</h3>
            <span className="bg-slate-900 text-white text-[9px] font-black px-1.5 py-0.5 rounded-md">{waitingTickets.length}</span>
          </div>
          <div className="flex-grow overflow-y-auto max-h-[350px] divide-y divide-slate-50">
            {waitingTickets.length === 0 ? (
              <div className="p-8 text-center text-slate-400">
                <p className="font-bold italic text-xs">Sin pendientes</p>
              </div>
            ) : (
              waitingTickets.map((t, idx) => (
                <div key={t.id} className="p-4 flex justify-between items-center hover:bg-slate-50 transition-colors animate-fade-in" style={{ animationDelay: `${idx * 0.05}s` }}>
                  <div>
                    <span className="text-[9px] font-black text-slate-400 uppercase block">Paciente • Espera: {getWaitTime(t.createdAt)}</span>
                    <span className="text-lg font-black text-slate-900 tracking-tighter">{t.code}</span>
                  </div>
                  <button 
                    onClick={() => onStatusUpdate(t.id, TicketStatus.CALLING, station.id)}
                    disabled={!!activeTicket}
                    className="px-4 py-2 bg-blue-600 text-white text-[10px] font-black uppercase tracking-widest rounded-lg hover:bg-blue-700 disabled:opacity-20 transition-all shadow-md shadow-blue-100"
                  >
                    Llamar
                  </button>
                </div>
              ))
            )}
          </div>
        </div>

        {/* Management Area */}
        <div className="lg:col-span-8">
          <div className="bg-white rounded-[2.5rem] shadow-xl shadow-slate-200/50 border border-slate-100 h-full min-h-[400px] flex flex-col justify-center text-center p-8">
            {activeTicket ? (
              <div className="space-y-6 animate-fade-in">
                <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-[0.2em] text-white mx-auto shadow-sm" style={{ backgroundColor: currentService?.color || '#333' }}>
                   <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/></svg>
                   {currentService?.name || 'Servicio Desconocido'}
                </div>

                <div>
                  <h1 className="text-[80px] font-black text-slate-900 leading-none tracking-tighter">{activeTicket.code}</h1>
                  <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest mt-1">Ticket en Atención</p>
                  <p className="text-[10px] text-blue-600 font-black uppercase tracking-widest mt-2">Ingresó a las {new Date(activeTicket.createdAt).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                </div>

                {activeTicket.status === TicketStatus.CALLING ? (
                  <div className="space-y-4 pt-4">
                    <div className="flex flex-col items-center gap-1.5">
                      <div className="flex gap-1">
                        <div className="w-1.5 h-1.5 bg-blue-600 rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
                        <div className="w-1.5 h-1.5 bg-blue-600 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></div>
                        <div className="w-1.5 h-1.5 bg-blue-600 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                      </div>
                      <p className="text-blue-600 font-black uppercase tracking-widest text-[11px]">Notificando Paciente</p>
                    </div>
                    <div className="flex justify-center gap-3">
                      <button 
                        onClick={() => onStatusUpdate(activeTicket.id, TicketStatus.ATTENDING, station.id)}
                        className="flex-1 max-w-[180px] py-4 bg-emerald-600 text-white font-black rounded-xl shadow-lg shadow-emerald-100 hover:bg-emerald-700 active:scale-95 transition-all text-base"
                      >
                        Iniciar
                      </button>
                      <button 
                        onClick={() => onStatusUpdate(activeTicket.id, TicketStatus.CANCELLED, station.id)}
                        className="px-6 py-4 bg-red-50 text-red-600 font-black rounded-xl hover:bg-red-100 active:scale-95 transition-all text-[10px] uppercase tracking-widest"
                      >
                        Ausente
                      </button>
                    </div>
                  </div>
                ) : (
                  <div className="space-y-6 pt-4">
                    <div className="bg-slate-50 inline-block px-8 py-4 rounded-2xl border border-slate-100">
                      <div className="text-4xl font-mono font-black text-slate-800 tracking-tight tabular-nums">
                        {formatTime(elapsedTime)}
                      </div>
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">Tiempo de Atención Actual</p>
                    </div>
                    <button 
                      onClick={() => onStatusUpdate(activeTicket.id, TicketStatus.COMPLETED, station.id)}
                      className="w-full max-w-[320px] py-4 bg-slate-900 text-white font-black rounded-xl shadow-xl shadow-slate-300 hover:bg-slate-800 active:scale-95 transition-all text-lg"
                    >
                      Finalizar Atención
                    </button>
                  </div>
                )}
              </div>
            ) : (
              <div className="space-y-4 py-8 opacity-60">
                <div className="w-24 h-24 bg-slate-50 rounded-[2rem] border border-slate-100 flex items-center justify-center mx-auto text-slate-200">
                  <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v4"/><path d="m16.2 7.8 2.9-2.9"/><path d="M18 12h4"/><path d="m16.2 16.2 2.9 2.9"/><path d="M12 18v4"/><path d="m4.9 19.1 2.9-2.9"/><path d="M2 12h4"/><path d="m4.9 4.9 2.9 2.9"/></svg>
                </div>
                <div className="max-w-xs mx-auto">
                  <h3 className="text-xl font-black text-slate-900 tracking-tight mb-1">Módulo Disponible</h3>
                  <p className="text-xs text-slate-500 font-medium leading-tight">Listo para el próximo paciente.</p>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default StaffView;
